class OpenXRViewerCore(CoreOpenXROpenGLMixin, CoreOpenXRD3D11Mixin, CoreOpenXRLifecycleMixin, CoreOpenXRInputMixin, CoreD3DInteropMixin, CoreCleanupMixin, CoreControllerActionsMixin, CoreControllerPoseMixin, CoreWindowInputMixin, CoreOverlayPanelsMixin, CoreScreenControlMixin, CoreLaserRenderMixin, CoreScreenStateMixin, CoreSourceStateMixin, CoreRuntimeEyeMixin, CoreFrameUploadMixin, CoreScreenQualityMixin, CoreQuadLayerMixin, CoreInputHelpersMixin, CoreKeyboardMixin, ControllerModelsMixin, CoreEnvironmentHooksMixin):
    """
    Renders the depth-parallax stereo views into a VR headset using OpenXR.

    A virtual flat screen is placed in world space at `screen_distance` meters.
    Head pose from xr.locate_views() provides proper 6DoF view matrices per eye.
    The screen can be repositioned/resized/rotated via keyboard or VR controller
    thumbsticks. An in-VR FPS/latency overlay quad sits just below the screen and
    is toggled with the menu button on the left controller.

    Parameters mirror the relevant subset of StereoWindow.__init__.
    Call run(first_rgb, first_depth) to enter the blocking frame loop.
    """

    def _effective_depth_strength(self):
        base = float(getattr(self, 'depth_strength', 0.0) or 0.0)
        ratio = float(getattr(self, '_depth_strength_ratio', 0.1) or 0.0)
        return base * ratio

    def _quantize_depth_strength(self, value):
        value = max(0.0, min(10.0, float(value)))
        return round(value * 10.0) / 10.0

    @property
    def depth_ratio(self):
        return self.depth_strength

    @depth_ratio.setter
    def depth_ratio(self, value):
        self.depth_strength = self._quantize_depth_strength(value)
        self._depth_strength_adjust_raw = self.depth_strength

    def __init__(
        self,
        depth_strength=1.0,
        convergence=0.0,
        frame_size=(1280, 720),
        fps=60,
        depth_q=None,
        show_fps=True,
        controller_model='pico',
        environment_model='Default',
        capture_mode='Monitor',
        monitor_index=1,
        **kwargs,
    ):
        self._controller_model = controller_model
        self._capture_mode = capture_mode
        self._input_monitor_index = monitor_index
        self.depth_strength = self._quantize_depth_strength(depth_strength)
        self._default_depth_strength = self.depth_strength
        self._depth_strength_adjust_raw = self.depth_strength
        self._depth_strength_ratio = 0.1
        self._depth_strength_local_override_until = 0.0
        self._stereo_enabled = True
        self._saved_depth_strength = self.depth_strength
        self.convergence = convergence
        self.frame_size = frame_size
        self.fps = fps
        self.depth_q = depth_q
        self.show_fps = show_fps
        self._runtime_config_callback = kwargs.get('runtime_config_callback')
        self._runtime_direct_source = False
        self._runtime_eye_has_frame = False
        self._runtime_eye_textures = [None, None]
        self._runtime_depth_texture = None
        self._runtime_eye_texture_size = None

        def _bool_env_option(key, env_name, default):
            value = kwargs.get(key, os.environ.get(env_name, default))
            return str(value or default).strip().lower() in ('1', 'true', 'yes', 'on')

        self._openxr_async_effects_enabled = _bool_env_option(
            'openxr_async_effects', 'D2S_OPENXR_ASYNC_EFFECTS', '1'
        )
        self._openxr_panorama_background_enabled = _bool_env_option(
            'openxr_panorama_background', 'D2S_OPENXR_PANORAMA_BACKGROUND', '1'
        )
        self._openxr_screen_upload_budget_ms = _float_option(
            kwargs,
            'openxr_screen_upload_budget_ms',
            'D2S_OPENXR_SCREEN_UPLOAD_BUDGET_MS',
            4.0,
            0.0,
            1000.0,
        )
        self._openxr_effect_submit_budget_ms = _float_option(
            kwargs,
            'openxr_effect_submit_budget_ms',
            'D2S_OPENXR_EFFECT_SUBMIT_BUDGET_MS',
            4.0,
            0.0,
            1000.0,
        )
        self._openxr_screen_upload_budget_skip_armed = False
        self._openxr_effect_submit_budget_skip_armed = False
        self._runtime_direct_enabled = str(
            kwargs.get('openxr_runtime_direct', os.environ.get('D2S_OPENXR_RUNTIME_DIRECT', '1')) or '1'
        ).strip().lower() not in ('0', 'false', 'no', 'off')
        self._runtime_eye_gpu_enabled = str(
            kwargs.get('openxr_runtime_eye_gpu_upload', os.environ.get('D2S_OPENXR_RUNTIME_EYE_GPU_UPLOAD', '1')) or '1'
        ).strip().lower() not in ('0', 'false', 'no', 'off')
        self._openxr_rgb_depth_feather = str(
            kwargs.get('openxr_rgb_depth_feather', os.environ.get('D2S_OPENXR_RGB_DEPTH_FEATHER', '0')) or '0'
        ).strip().lower() in ('1', 'true', 'yes', 'on')
        self._openxr_rgb_depth_shader_resolution = str(
            kwargs.get('openxr_rgb_depth_shader_resolution', os.environ.get('D2S_OPENXR_RGB_DEPTH_SHADER_RESOLUTION', 'source')) or 'source'
        ).strip().lower()
        if self._openxr_rgb_depth_shader_resolution not in ('source', 'swapchain', 'unset'):
            self._openxr_rgb_depth_shader_resolution = 'source'
        self._openxr_rgb_depth_shader_resolution_logged = False
        self._runtime_eye_gpu_logged = False
        # CUDA/GL image interop requires RGBA textures.  Use it as the primary
        # runtime eye upload path; PBO remains a GPU fallback when image upload
        # is explicitly disabled or fails with a logged reason.
        self._runtime_eye_texture_gpu_enabled = str(
            kwargs.get(
                'openxr_runtime_eye_texture_gpu_upload',
                os.environ.get('D2S_OPENXR_RUNTIME_EYE_TEXTURE_GPU_UPLOAD', '1'),
            ) or '1'
        ).strip().lower() in ('1', 'true', 'yes', 'on')
        self._runtime_eye_texture_components = 4
        self._runtime_eye_texture_logged = False
        self._runtime_eye_cpu_logged = False
        self._runtime_eye_diff_logged = False
        self._runtime_eye_gpu_disabled_reason = None
        self._screen_footprint_logged = set()
        self._runtime_eye_texture_resources = [None, None]
        self._runtime_eye_texture_resource_size = None
        self._runtime_eye_pbos = [None, None]
        self._runtime_eye_cuda_resources = [None, None]
        self._runtime_eye_pbo_size = None
        self._runtime_eye_pbo_nbytes = 0
        self._openxr_perf_log = str(
            kwargs.get('openxr_perf_log', os.environ.get('D2S_OPENXR_PERF_LOG', '0')) or '0'
        ).strip().lower() in ('1', 'true', 'yes', 'on')

        self._screen_grab_local_l = None
        self._screen_grab_local_r = None
        self._right_grip_screen_rotation_enabled = str(
            kwargs.get('openxr_right_grip_screen_rotation', os.environ.get('D2S_OPENXR_RIGHT_GRIP_SCREEN_ROTATION', '0')) or '0'
        ).strip().lower() in ('1', 'true', 'yes', 'on')
        # Keyboard grip-to-move anchor -local (lx, ly) on keyboard plane
        # at the moment the grip was pressed.  Mirrors _screen_grab_local_*.
        self._kb_grab_local_l     = None
        self._kb_grab_local_r     = None
        # Standalone offsets for keyboard orientation, applied on top of the
        # auto-orientation that aims the panel at the head.  Defaults are 0
        # because the auto-orientation already produces the natural tilt that
        # makes the keyboard face the head (e.g. a keyboard below the head
        # gets a negative base_pitch that tilts the surface up toward the user).
        self._kb_yaw_offset       = 0.0
        self._kb_pitch_offset     = 0.0
        # Per-hand grip lock -once a grip press latches onto 'screen' or
        # 'keyboard', it stays there until release.  Enforces "only grip one
        # item at a time" so a single press cannot jump between objects.
        self._grip_target_l       = None   # None | 'screen' | 'keyboard'
        self._grip_target_r       = None
        # Suppress keyboard typing while any grip is held (avoids accidental
        # key presses while repositioning the keyboard).
        self._grip_l_now          = False
        self._grip_r_now          = False
        self._haptic_last_l       = 0.0
        self._haptic_last_r       = 0.0
        self._ctrl_press_l        = {}
        self._ctrl_press_r        = {}


        # FPS display -timestamp ring: (len-1)/(last-first) is exact over the window
        self.actual_fps      = 0.0   # XR composition rate (this loop)
        self.sbs_fps         = 0.0   # SBS source rate (depth_q producer in main.py)
        self.total_latency   = 0.0
        self._frame_ts_ring  = collections.deque(maxlen=60)  # ~1 s at 60 Hz
        self._sbs_ts_ring    = collections.deque(maxlen=60)  # SBS frame arrivals

        # Overlay redraw throttle -texture is rebuilt at most once per second
        self._last_overlay_update   = 0.0
        self._cached_actual_fps     = 0.0
        self._cached_sbs_fps        = 0.0
        self._cached_latency        = 0.0
        self._cached_screen_width   = 0.0
        self._cached_screen_height  = 0.0
        self._cached_screen_dist    = 0.0
        self._cached_depth_strength = 1.0
        self._cached_vr_res         = (0, 0)
        self._cached_sbs_res        = (0, 0)

        # Virtual screen transform (world space, metres / radians)
        self.screen_distance = _float_option(kwargs, 'openxr_screen_distance', 'D2S_OPENXR_SCREEN_DISTANCE', 16.0, 0.25, 40.0)
        self.screen_width    = _float_option(kwargs, 'openxr_screen_width', 'D2S_OPENXR_SCREEN_WIDTH', 16.0, 0.25, 30.0)
        self._initial_screen_preset = ('Headset Recommended', self.screen_width, self.screen_distance) if (
            'openxr_screen_width' in kwargs or 'openxr_screen_distance' in kwargs
        ) else None
        self._screen_ref_size = self.screen_width   # long-dimension reference for resize
        self.screen_height   = None   # derived from frame aspect ratio on first frame

        # Environment-screen mode: keep a plain fixed screen, no visual effects.
        self._corner_radius = 0.0

        # Environment model (glTF 3D scene) -loaded from environment/environment.glb
        self._environment_model = str(environment_model or 'Default')
        # Thin entry modules can pass environment_model='None' to run without
        # loading or rendering any room/environment scene.
        self._environment_enabled = self._environment_model.strip().lower() != 'none'
        self._environment_root = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'environments')
        self._available_environment_models = self._discover_environment_models()
        self._env_profile = {}
        self._screen_profile = {}
        self._view_pose_profile = {}
        self._view_pose_profiles = []
        self._view_pose_index = 0
        self._lighting_presets = []
        self._lighting_preset_index = 0
        self._active_environment = None
        self._settings_sync_dirty = False
        self._settings_sync_save_t = 0.0
        self._glow_intensity = float(kwargs.get('glow_intensity', 0.65))
        self._glow_width_m = float(kwargs.get('glow_width', 0.16))
        self._glow_surround_margin_m = float(kwargs.get('glow_surround_margin', 14.0))
        self._glow_intensity_multiplier = float(kwargs.get('glow_intensity_multiplier', 0.0))
        self._glow_shell_intensity_multiplier = float(kwargs.get('glow_shell_intensity_multiplier', 0.0))
        self._glow_shell_radius_m = float(kwargs.get('glow_shell_radius', 18.0))
        self._glow_shell_height_m = float(kwargs.get('glow_shell_height', 8.5))
        self._frosted_glow_intensity = float(kwargs.get('frosted_glow_intensity', 2.2))
        self._frosted_glow_alpha = float(kwargs.get('frosted_glow_alpha', 0.42))
        self._frosted_glow_threshold = float(kwargs.get('frosted_glow_threshold', 0.46))
        self._frosted_glow_lod = float(kwargs.get('frosted_glow_lod', 5.4))
        self._frosted_glow_margin_m = float(kwargs.get('frosted_glow_margin', 3.6))
        self._frosted_glow_blend = float(kwargs.get('frosted_glow_blend', 2.40))
        self._frosted_glow_thickness = float(kwargs.get('frosted_glow_thickness', 2.40))
        self._frosted_glow_inset = float(kwargs.get('frosted_glow_inset', 0.045))
        self._frosted_glow_diffuse = float(kwargs.get('frosted_glow_diffuse', 0.85))
        self._frosted_veil_intensity = float(kwargs.get('frosted_veil_intensity', 1.65))
        self._frosted_veil_alpha = float(kwargs.get('frosted_veil_alpha', 0.58))
        self._frosted_veil_lod = float(kwargs.get('frosted_veil_lod', 6.2))
        self._frosted_veil_threshold = float(kwargs.get('frosted_veil_threshold', 0.22))
        self._frosted_veil_scale = float(kwargs.get('frosted_veil_scale', 1.22))
        self._frosted_veil_beam_mix = float(kwargs.get('frosted_veil_beam_mix', 0.22))
        self._glow_mode = str(kwargs.get('glow_mode', 'screen')).strip().lower() or 'screen'
        self._glow_ref_screen = float(kwargs.get('glow_ref_screen', 2.4))
        self._glow_color = tuple(kwargs.get('glow_color', (0.30, 0.55, 1.0)))
        self._screen_light_intensity = float(kwargs.get('screen_light_intensity', 3.5))
        self._controller_hdr_lighting = bool(kwargs.get('controller_hdr_lighting', False))
        self._env_model_path = None
        self._env_model_prims = []        # list of {'vao', 'vbo', 'ibo', 'tex_key', 'tri_count'}
        self._scene_lights = []            # KHR_lights_punctual lights
        self._env_model_tex_cache = {}    # cache_key -> moderngl Texture
        self._env_model_visible = False   # hidden by default, toggle with N key
        self._env_model_pos = [0.0, -1.0, -3.0]   # world-space position (x, y, z)
        self._env_model_rot = [0.0, 0.0, 0.0]     # Euler rotation (yaw, pitch, roll) in radians
        self._env_model_scale = [1.0, 1.0, 1.0]   # scale factor (x, y, z)
        self._env_model_init_done = False  # lazy init: tried loading gltf once
        # Viewer-side room lighting.  glTF emissive surfaces do not light other
        # surfaces, so XR uses a small fixed light rig unless the GLB provides
        # KHR_lights_punctual lights.
        self._env_head_light_color = tuple(kwargs.get('env_head_light_color', (0.24, 0.24, 0.26)))
        self._env_ambient_color = tuple(kwargs.get('env_ambient_color', (0.14, 0.13, 0.15)))
        self._env_fallback_dir = np.array(kwargs.get('env_directional_dir', (0.25, -0.82, -0.52)), dtype=np.float32)
        self._env_fallback_dir = self._env_fallback_dir / (np.linalg.norm(self._env_fallback_dir) + 1e-8)
        self._env_fallback_dir_color = tuple(kwargs.get('env_directional_color', (0.34, 0.31, 0.28)))
        self._env_fill_lights = list(kwargs.get('env_fill_lights', [
            {'position': (-0.9, 1.45, -2.4), 'color': (0.55, 0.30, 0.46), 'range': 3.8},
            {'position': (1.35, 1.10, -3.3), 'color': (0.24, 0.32, 0.46), 'range': 4.6},
        ]))
        self._env_exposure = float(kwargs.get('env_exposure', 1.12))
        self._env_gamma = float(kwargs.get('env_gamma', 2.2))
        self._env_emissive_strength = float(kwargs.get('env_emissive_strength', 0.85))
        self._env_khr_light_scale = float(kwargs.get('env_khr_light_scale', 1.0))
        self._env_render_quality = str(kwargs.get('env_render_quality', 'balanced')).strip().lower()
        self._env_shading_mode = str(kwargs.get('env_shading_mode', 'pbr')).strip().lower()
        self._env_texture_anisotropy = float(kwargs.get('env_texture_anisotropy', 16.0))
        self._env_perf_log = bool(kwargs.get('env_perf_log', False))
        self._env_perf_last_log = 0.0
        self._env_perf_accum_ms = 0.0
        self._env_perf_samples = 0
        self._xr_render_scale = max(0.5, min(2.0, float(kwargs.get('xr_render_scale', 1.0))))
        self._screen_quality_filter = bool(kwargs.get('screen_quality_filter', False))
        self._screen_quality_sharpness = max(0.0, min(1.0, float(kwargs.get('screen_quality_sharpness', 0.35))))
        self._screen_quality_oversample = max(0.75, min(1.5, float(kwargs.get('screen_quality_oversample', 1.0))))
        self._xr_quad_layer_active = False
        self._xr_quad_layer_failed = False
        self._xr_quad_layer_failure_reason = None
        self._xr_quad_layer_debug_offset = float(kwargs.get('xr_quad_layer_debug_offset', 0.0))
        self._xr_quad_layer_stereo_boost = max(1.0, float(kwargs.get('xr_quad_layer_stereo_boost', 1.0)))
        self._xr_quad_layer_debug_logged = False
        self._env_base_settings = {
            'model_pos': list(self._env_model_pos),
            'model_rot': list(self._env_model_rot),
            'model_scale': list(self._env_model_scale),
            'head_light_color': tuple(self._env_head_light_color),
            'ambient_color': tuple(self._env_ambient_color),
            'fallback_dir': self._env_fallback_dir.copy(),
            'fallback_dir_color': tuple(self._env_fallback_dir_color),
            'fill_lights': list(self._env_fill_lights),
            'exposure': self._env_exposure,
            'gamma': self._env_gamma,
            'emissive_strength': self._env_emissive_strength,
            'khr_light_scale': self._env_khr_light_scale,
            'render_quality': self._env_render_quality,
            'shading_mode': self._env_shading_mode,
            'texture_anisotropy': self._env_texture_anisotropy,
            'perf_log': self._env_perf_log,
            'xr_render_scale': self._xr_render_scale,
            'screen_quality_filter': self._screen_quality_filter,
            'screen_quality_sharpness': self._screen_quality_sharpness,
            'screen_quality_oversample': self._screen_quality_oversample,
            'xr_quad_layer_debug_offset': self._xr_quad_layer_debug_offset,
            'xr_quad_layer_stereo_boost': self._xr_quad_layer_stereo_boost,
            'screen_light_intensity': self._screen_light_intensity,
            'controller_hdr_lighting': self._controller_hdr_lighting,
        }
